select * from dw_developer.tabledictionary where tpktablename like '%t_%'
select TOP 10000 * from [Wholesale_ProductSourcing_AFI].[Bookings]
select dISTINCT BokContainerSize  from [Wholesale_ProductSourcing_AFI].[Bookings]

SELECT top 10 *
        --ROW_NUMBER() OVER (PARTITION BY BokTripNumBer ORDER BY BokTripCreateDate DESC) AS rn
FROM [Wholesale_ProductSourcing_AFI].[Bookings]
WHERE BokWarehouse = '335' AND BokContainerNumBer LIKE 'HLBU270787%'
   

    SELECT BokTripNumber,BokContainerNumBer,BokContainerSize, 
           ROW_NUMBER() OVER (PARTITION BY BokTripNumber,BokContainerNumBer ORDER BY BokTripCreateDate DESC) AS rn
    FROM [Wholesale_ProductSourcing_AFI].[Bookings]
    WHERE BokWarehouse = '335' and BokTripCreateDate > DATEADD(DAY, -400, GETDATE())



--??
WITH LatestBookings AS (
    SELECT BokTripNumber,BokContainerNumBer,
           ROW_NUMBER() OVER (PARTITION BY BokTripNumber,BokContainerNumBer ORDER BY BokTripCreateDate DESC) AS rn
    FROM [Wholesale_ProductSourcing_AFI].[Bookings]
    WHERE BokWarehouse = '335'
)
SELECT t.*, d.tpkModified
FROM LatestBookings AS t
CROSS JOIN (SELECT tpkModified FROM dw_developer.tabledictionary WHERE tpktablename LIKE 'Bookings') AS d
WHERE t.rn = 1
--AND t.BokTripStatusCode NOT IN ('P')
AND t.BokContainerNumBer IN ('OOLU899910','CSNU562396')
AND t.BokTripNumBer = '4259'
  AND t.BokTripCreateDate > DATEADD(DAY, -120, GETDATE())
ORDER BY t.BokTripNumBer, t.BokTripCreateDate;




select top 100 * from dw_developer.tabledictionary
where tpktablename like '%Bookings%'

select top 100 * from dw_developer.tabledictionary
where tpktablename like 'BookingActions'

SELECT  * FROM  [Wholesale_ProductSourcing_AFI].[BookingActions] as t where t.BacWarehouse = '335' and t.BacTripNumBer in ('90971')
order by t.BacTripNumBer, t.dtea

SELECT * FROM  [Wholesale_ProductSourcing_AFI].[Bookings] as t where t.BokWarehouse = '335' and t.BokTripNumBer in ('90971')
order by t.BokTripNumBer, t.BokTripCreateDate

SELECT  top 10 * FROM  Wholesale_ProductSourcing_AFI.BarCodes



WITH LatestBookings AS (
    SELECT *, 
           ROW_NUMBER() OVER (PARTITION BY BokTripNumBer ORDER BY BokTripCreateDate DESC) AS rn
    FROM [Wholesale_ProductSourcing_AFI].[Bookings]
    WHERE BokWarehouse = '335'
)
SELECT t.*, d.tpkModified
FROM LatestBookings AS t
CROSS JOIN (SELECT tpkModified FROM dw_developer.tabledictionary WHERE tpktablename LIKE 'Bookings') AS d
WHERE t.rn = 1
--AND t.BokTripStatusCode NOT IN ('P')
AND t.BokTripCreateDate > DATEADD(DAY, -120, GETDATE())
ORDER BY t.BokTripNumBer, t.BokTripCreateDate;




WITH LatestBookings AS (
    SELECT *, 
           ROW_NUMBER() OVER (PARTITION BY BokTripNumBer ORDER BY BokTripCreateDate DESC) AS rn
    FROM [Wholesale_ProductSourcing_AFI].[Bookings]
    WHERE BokWarehouse = '335'
)
SELECT t.*
FROM LatestBookings as t
WHERE t.rn = 1
	and BokTripStatusCode not in ('P')
	and BokTripCreateDate > '2024-01-01' 
ORDER BY t.BokTripNumBer, t.BokTripCreateDate;


